    var combineHighlightWords = function combineHighlightWords(dataList) {
      // 如果已初始化过则返回；templateID <= -1 时还需判断 gitcode 请求是否完成
      newHighlightRequestData = dataList;
      if (initedNewHighlight || cJTemplateJudgement <= -1 && gitcodePending) {
        return;
      }

      // 标记为已初始化，避免重复处理
      initedNewHighlight = true;

      // 一次遍历：去重、填充 newHighlightDataMap、添加 cache、执行高亮替换
      for (var i = 0, len = dataList.length; i < len; i++) {
        var item = dataList[i];
        var keywordLower = (item.word || '').toLowerCase();
        if (!keywordLower || gitcodeMap.has(keywordLower)) {
          continue;
        }
        if (typeof item.cache === 'undefined') {
          item.cache = 0;
        }
        newHighlightDataMap.set(keywordLower, item);
      }
      newHighlightReplace();
    };

